    /// <summary>
    /// COMPOSITION ROOT
    /// Responsável por construir o grafo de dependências da aplicação.
    /// Centraliza a criação de instâncias e a injeção de dependências.
    ///
    /// 🔬 FASE 1 — KILL SWITCH DO LEGADO
    /// AdaptadorLimbic agora opera apenas em RNA.
    /// MotorDeIdentidade permanece ativo somente para ACL do Fenótipo.
    /// </summary>
    public static class RaizComposicao
    {
        public static List<IModuloAnalise> ConstruirPipeline(string diretorioBase)
        {

            // ======================================================
            // 🔎 SCAN ZUMBIS (usa raiz do código, não sandbox)
            // ======================================================
            var raizCodigo = Directory
                .GetParent(AppContext.BaseDirectory)!
                .Parent!.Parent!.Parent!.FullName;

            Scriptome.Infrastructure.ZumbiScanner.Escanear(raizCodigo);
            // ======================================================
            // 1. CONFIGURAÇÃO DE CAMINHOS
            // ======================================================
            string caminhoVocabulario = Path.Combine(diretorioBase, "Data", "Sandbox");



            // ======================================================
            // 2. SERVIÇO DE VOCABULÁRIO
            // ======================================================
            IServicoVocabulario vocabularioService = new BancoDeDadosLexico();

            try
            {
                Console.WriteLine($"[BOOT] Carregando Vocabulário de: {caminhoVocabulario}");
                vocabularioService.Carregar(caminhoVocabulario);
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"[ERRO] Falha crítica ao carregar léxico: {ex.Message}");
                Console.ResetColor();
            }

            // ======================================================
            // 3. CONFIGURAÇÃO DERIVA
            // ======================================================
            var configVader = new ParametrosVader();
            IMotorDeriva derivaEngine = new MotorDeriva6(vocabularioService, configVader);

            // ======================================================
            // 4. MOTOR LÍMBICO
            // ======================================================
            var motorLimbic = new MotorLimbic(vocabularioService, derivaEngine);



            // SERÁ REMOVIDO COM REFATORAÇÃO DO ETOGRAMA (SOON TO BE DEAD)
            // ======================================================
            // 5. PIPELINE DE CLASSIFICADORES LEGADO
            // (Mantido para ACL do Fenótipo)
            // ======================================================
            var individuais = new List<IClassificadorIndividual>
            {
                new ClassificadorIntensidade(),
                new ClassificadorTermico(),
                new ClassificadorPsicodinamico(),
                //new ClassificadorLacaniano(),
                //new ClassificadorMBTI(),
                new ClassificadorJung(),
                new ClassificadorScriptome()
            };

            var extrator = new ExtratorEtogramaDeriva6();
            var classificadorCartesiano =
                new ClassificadorEtogramaCartesiano(BibliotecaCentroidesEtograma.Criar());

            IMotorEtogramaCartesiano motorCartesiano =
                new MotorEtogramaCartesiano3D(extrator, classificadorCartesiano);

            var motorIdentidade = new MotorDeIdentidade(individuais, motorCartesiano);


            // ======================================================
            // 6. MOTOR IDENTIDADE RNA (OFICIAL)
            // ======================================================
            IMotorSplicing splicing = new MotorSplicing();

            var jungRNA = new ClassificadorJungV2(splicing);
            var lacanRNA = new ClassificadorLacanianoV2(splicing);
            var mbtiRNA = new ClassificadorMBTIV2(splicing);
            var narrativaRNA = new ClassificadorNarrativaV2(splicing);

            IMotorIdentidadeRNA motorIdentidadeRNA =
                new MotorIdentidadeRNA(
                    jungRNA,
                    mbtiRNA,
                    lacanRNA,
                    narrativaRNA
                );

            // ======================================================
            // 7. CONSTRUÇÃO DO PIPELINE
            // ======================================================
            return new List<IModuloAnalise>
            {
                new AdaptadorBasico(),

                // 🧬 FASE 1 — RNA MODE
                new AdaptadorLimbic(
                    motorLimbic,
                    motorIdentidadeRNA
                ),

                new AdaptadorInteracao(),
                new AdaptadorBeats(),
                new AdaptadorDuracao(),
                new AdaptadorDinamica()
            };

            
        }
    }
