using System;
using System.IO;
using System.Text.Json;

namespace Scriptome.Infrastructure.Baseline
{
    /// <summary>
    /// Exportador de Golden Master.
    /// 
    /// - Serializa qualquer objeto determinístico.
    /// - Não pertence ao domínio.
    /// - Preparado para futura migração para testes automatizados.
    /// </summary>
    public static class ExportadorBaselineEtograma
    {
        private static readonly JsonSerializerOptions _opcoes =
            new JsonSerializerOptions
            {
                WriteIndented = true,
                PropertyNamingPolicy = null
            };

        public static void Exportar<T>(
            T objeto,
            string caminhoArquivo)
        {
            if (objeto == null)
                throw new ArgumentNullException(nameof(objeto));

            var json = JsonSerializer.Serialize(objeto, _opcoes);

            var pasta = Path.GetDirectoryName(caminhoArquivo);
            if (!Directory.Exists(pasta))
                Directory.CreateDirectory(pasta!);

            File.WriteAllText(caminhoArquivo, json);
        }
    }
}

