    /// Responsável por carregar baseline previamente congelado.
    /// 
    /// Futuramente será usado por testes automatizados.
    /// </summary>
    public static class LeitorBaseline
    {
        public static T Carregar<T>(string caminhoArquivo)
        {
            if (!File.Exists(caminhoArquivo))
                throw new FileNotFoundException(
                    "Baseline não encontrado.",
                    caminhoArquivo);

