using System;
using System.Collections.Generic;
using System.Text;


    namespace Scriptome.Infrastructure.Validador
    {
        public static class MetricasDivergencia
        {
            public static double CalcularTaxaDivergencia(
                IEnumerable<ComparacaoJung> comparacoes)
            {
                int total = comparacoes.Count();
                if (total == 0) return 0;

                int divergentes =
                    comparacoes.Count(c => !c.SaoIguais);

                return (double)divergentes / total;
            }
        }
    }

